const GenericResource = require("./generic-resource");

class Subscriptions extends GenericResource {
    constructor(config){
        super(config);

        this.resource = '/subscriptions';
    }

    restore = (id)=>{
        let promise = new Promise((resolve, reject)=>{
            reject('A API Asaas não permite restaurar assinaturas!');
        });
        
        return promise;
    }
}

module.exports = Subscriptions;